#include<bits/stdc++.h>
using namespace std;
int main()
{
	long long n,a[1000000],i,j,t=1,ans=0;
	cin>>n;
	for(i=0;i<n;i++)
	{
		cin>>a[i];
	}
	for(j=0;j<n;j++)
	{
			if(a[j+1]>a[j])
			{
				t++;
				if(t>ans)
				ans=t;
			}
			else
			t=1;
	}
	cout<<ans;
	return 0;
}
